import Spinner from './Spinner';
import TodoInput from './TodoInput';
import classes from './TodoItems.module.css'
import TodoList from './TodoList';
import { useState } from 'react'
import * as taskService from '../services/taskService'
import TaskAction from '../components/UserListConstants'
import EditTask from './EditTask';
import DeleteTask from './DeleteTask';
import App from '../App';



const TodoItems = (props,loader) => {

      const [taskAction, setTaskAction]=useState({
        task:null,
        action:null,
      })

const taskActionClickHandler = (id, actionType) =>{
        taskService.getOne(id)
        .then(task=>{
            setTaskAction({
                task,
                action:actionType
            })
        })
    }


return (
<section className={classes['todo-items-section']}>
{taskAction.action === TaskAction.Edit && <EditTask closeClick={props.clickCloseHandler} editTaskHandler={props.editTaskHandler} task={taskAction.task} />}
{taskAction.action === TaskAction.Delete && <DeleteTask clickCloseHandler={props.clickCloseHandler} closeClick={props.clickCloseHandler} task={taskAction.task}/>}
{props.loading && <Spinner/>}
 <ul className={classes['list-wrapper']}>
{props.task.map(x=>  <TodoList key={x.id} detailsHandler={taskActionClickHandler}  {...x}/>)}
</ul>
</section>
);
}

export default TodoItems
